                Term::Str(package_artifact),
            ),
            (
                TermOrdKey(Term::symbol(":artifact")),
                Term::Map(
                    [
                        (
                            TermOrdKey(Term::symbol(":package")),
                            Term::Str(executable_bundle.package_path.display().to_string()),
